var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"묘지 안쪽에 이런 공간이 있을 줄은…….","JPN":"墓地の奥にこんな空間があるなんて……","ENG":"Didn't expect a place like this inside the cemetery...","TWN":"沒想到墓地裡面會有這樣的空間……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"아무래도 저택 지하랑 이어지는 길인 것 같네.","JPN":"どうやら邸宅の地下と繋がってる通路っぽいわね。","ENG":"Looks like it connects to the mansion's underground.","TWN":"看來這條路通向屋子的地下。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"상태는 어때, 멍멍이?","JPN":"状況はどう？　ワンちゃん。","ENG":"How are you holding up, Puppy?","TWN":"怎麼樣了，狗狗？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"팔팔하죠.","JPN":"絶好調です。","ENG":"Still going strong.","TWN":"好得很呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"피 냄새도 계속 이어지고 있어요.","JPN":"血の匂いもずっと続いてます。","ENG":"The blood scent is still leading the way.","TWN":"血腥味也一直持續著。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"계속 추적할 생각이야?","JPN":"まだ追跡するつもり？","ENG":"Are you planning to keep following it?","TWN":"打算繼續追蹤嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"끄응…… 저도 잘 모르겠네요.","JPN":"うーん……私もよくわかりません。","ENG":"Hmm... I'm not sure.","TWN":"嗯……我也不知道。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"분명 머리로는 이제 돌아가야 한다는 걸 아는데.","JPN":"確かに頭ではもう帰った方がいいってわかっているんですけど。","ENG":"I know in my head that I should turn back, but...","TWN":"雖然腦子裡清楚現在該回去了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭔가 마음에 걸리는 게 있구나?","JPN":"何か引っかかることがあるのね。","ENG":"Something's bothering you, isn't it?","TWN":"你是有什麼不放心的地方嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네. 사실 묘지 앞에서 맡았던 그 썩은 내.","JPN":"はい。実は墓地の前で嗅いだあの腐った匂い。","ENG":"Yeah. That rotting stench I smelled at the entrance to the cemetery...","TWN":"嗯，其實在墓地前聞到的那股腐臭味，"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"처음 맡은 게 아니에요.","JPN":"初めてじゃないんです。","ENG":"It wasn't the first time I smelled it.","TWN":"應該不是第一次聞到的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그건 악령의 냄새도, 침식체의 냄새도 아니거든요.","JPN":"あれは悪霊の匂いでも、侵食体の匂いでもありません。","ENG":"It wasn't the scent of an evil spirit or a C.O.","TWN":"那既不是惡靈的味道，也不是侵蝕體的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"관리국 재난 경보.","JPN":"管理局災難警報。","ENG":"The disaster alert from the Administration.","TWN":"管理局災難警報。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_POLICE"},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"하늘을 보지 마십시오.","JPN":"空を見ないでください。","ENG":"Do not look at the sky.","TWN":"請不要看天空。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"지옥의 냄새였어요.","JPN":"地獄の匂いでした。","ENG":"It was the scent of hell.","TWN":"是地獄的味道。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 수녀가 왜 여기 있는지는 모르겠지만…….","JPN":"あのシスターがどうしてここにいるのかはわかりませんが……","ENG":"I don't know why that nun is here...","TWN":"不知道那個修女為什麼會在這裡……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"분명 관련이 있을 거예요.","JPN":"きっと関係があるはずです。","ENG":"But she's definitely connected to that.","TWN":"肯定和她有關係。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"어쩐지, 손해 보면 입에 거품을 물던 애가 왜 이러나 싶었어.","JPN":"なるほど、損をすると発狂していたあなたにしては珍しいと思ったわ。","ENG":"I was wondering why the girl who foams at the mouth over a small loss was suddenly acting so different.","TWN":"怪不得，我還在想那個一吃虧就大發雷霆的傢伙怎麼會這樣。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"진작 말하지. 못 들어줄 일도 아닌데.","JPN":"早く言ってくれればよかったのに。反対しなかったはずよ？","ENG":"You should've said something earlier. It's not like I'd refuse.","TWN":"你為什麼不早說，這又不是不能說的事。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아직도 갈등 중이거든요.","JPN":"まだ迷ってるんです。","ENG":"I'm still debating it.","TWN":"現在還在糾結中呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이대로 돌아가느냐, 끝까지 가느냐.","JPN":"このまま帰るか、最後まで行くか。","ENG":"Do I turn back or see this through?","TWN":"就這樣回去，還是堅持到底。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"적어도 저 수녀가 이 일과 관련이 있는지만 확인하고 싶어요.","JPN":"少なくともあのシスターが今回のことと関係があるかどうかだけは確認したいんです。","ENG":"At the very least, I need to confirm whether that nun is involved.","TWN":"至少想確認一下那位修女是否與此事有關。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 다음엔?","JPN":"その後は？","ENG":"And after that?","TWN":"接下來呢？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뜯을 수 있는 건 다 뜯어야죠.","JPN":"取れるものは全部ぶんどってやりますよ。","ENG":"I'll take everything I can.","TWN":"能拆的都要拆下來。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"책도 엄청 비싸게 팔 수 있을 것 같던데요?","JPN":"本もめっちゃ高く売れそうなんです。","ENG":"That book looks like it could fetch a very high price.","TWN":"書好像也能賣得很貴吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흐, 흐흐…….","JPN":"ふ、ふふ……","ENG":"Hehe... Hehehe...","TWN":"嗯，嗯嗯……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"기다리고 있었네.","JPN":"待っていたぞ。","ENG":"I've been waiting.","TWN":"我在等你。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L1_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"좋은 소식이 있으면 하네만…….","JPN":"いい知らせがあればいいが……","ENG":"I hope you have good news.","TWN":"如果有好消息的話……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아쉽게도, 꽤 골치 아픈 녀석이 남은 것 같더군요.","JPN":"残念ですが、かなり手強いやつが残っているようです。","ENG":"Unfortunately, there's still a troublesome one left.","TWN":"可惜，好像還剩下一個相當棘手的傢伙。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그리고…… 악령을 쫓던 도중, 사망자를 발견했습니다.","JPN":"それに……悪霊を追いかけていた途中、死亡者を見つけました。","ENG":"And... while chasing the evil spirit, I found a dead body.","TWN":"而且……在驅逐惡靈的過程中，發現了死者。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"사망자? 분명 사람들은 모두 내보냈을 텐데……?","JPN":"死亡者？　確かに人は全部外に出したはずだが……？","ENG":"A body? But I made sure everyone had evacuated...","TWN":"死者？明明所有人都已經撤離了……？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이유는 저도 모르죠.","JPN":"どういう経緯かは私もわかりません。","ENG":"I wouldn't know why.","TWN":"原因我也不知道。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"중요한 건, 그 악령이 수녀에게 빙의했다는 거예요.","JPN":"大事なのは、その悪霊がシスターに憑りついているということです。","ENG":"What matters is that the evil spirit has possessed a nun.","TWN":"重要的是，那惡靈附身在修女身上了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어중이떠중이를 들였다간 악령에 씔 수 있다고 그렇게 말씀드렸는데.","JPN":"素人を入れると悪霊に憑りつかれる可能性があるとあれほど申し上げたはずですが。","ENG":"I did warn you that amateurs could end up getting possessed.","TWN":"我不是告訴過你，如果隨便找些人來，他們會被惡靈附身的嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"수녀? 나는 수녀를 부른 적이 없네.","JPN":"シスター？　私はシスターなぞ呼んでいないぞ。","ENG":"A nun? I never called for a nun.","TWN":"修女？我可沒叫修女來。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……그럼 불법 침입자로군요?","JPN":"……では不法侵入者なのですね？","ENG":"...Then she's trespassing?","TWN":"……那就是非法入侵者了？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그렇다고 볼 수 있지.","JPN":"そういうことになる。","ENG":"That would be accurate.","TWN":"可以這麼認為。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"더는 선조들의 땅이 더럽혀지는 걸 원치 않네.","JPN":"これ以上先祖の地が荒らされるのは御免だ。","ENG":"I won't allow my ancestors' land to be desecrated any further.","TWN":"我不希望祖先的土地再被玷污。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"무슨 방법을 써서라도 그 악령을 제거해 주게.","JPN":"どんな手を使ってでもその悪霊を取り除いてくれ。","ENG":"No matter what it takes, I want that evil spirit eliminated.","TWN":"無論用什麼方法，都要除掉那個惡靈。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무슨 방법을 써서라도……라면?","JPN":"どんな手を使ってでも……とおっしゃいますと？","ENG":"No matter what it takes...?","TWN":"無論用什麼……方法？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"수녀의 신변에 무슨 일이 생겨도 상관없다는 걸세.","JPN":"そのシスターの身に何かあっても関係ないという意味だ。","ENG":"Her safety is of no concern to me.","TWN":"即使修女出了什麼事也無所謂。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"감히…… 내 땅에 허락받지 않은 자가…….","JPN":"よくも……私の領地に許可もなく……","ENG":"How dare she enter my land uninvited...","TWN":"竟敢……擅自闖入我的領地……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"빙의자의 제령은 조금 까다로워요.","JPN":"憑りつかれた人の除霊は少し厄介です。","ENG":"Exorcising a possessed person is a little tricky.","TWN":"附身者的驅魔有點棘手。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"추가 비용이 더 청구됩니다만, 괜찮으실지?","JPN":"追加費用を上乗せして請求いたしますが、大丈夫でしょうか？","ENG":"There will be an additional fee. Will that be all right?","TWN":"會額外收取費用，可以接受嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그까짓 의뢰 보수는 나한텐 푼돈이야!","JPN":"そんな依頼報酬、私には小銭だ！","ENG":"That's chump change to me!","TWN":"那點委託報酬對我來說只是小錢而已！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"서두르게!","JPN":"急いでくれ！","ENG":"Now, hurry!","TWN":"快點開始吧！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"넵!","JPN":"はいっ！","ENG":"Yes, sir!","TWN":"好的！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};